import {
  ConnectedPosition,
  Overlay,
  OverlayConfig,
  OverlayRef,
} from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  TemplateRef,
  ViewChild,
  ViewContainerRef,
  computed,
  forwardRef,
  inject,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';
import { Subscription } from 'rxjs';
import { injectFormControl } from '../../utils/form-control';
import { mergeClasses } from '../../utils/merge-classes';
import { LabelComponent } from '../label';
import { DatepickerCalendarComponent } from './datepicker-calendar.component';
import {
  DATEPICKER_CTX,
  type DatepickerContext,
  type DatepickerSize,
  type DisabledDateFn,
} from './datepicker.tokens';
import { datepickerTriggerVariants } from './datepicker.variants';
import { formatDate, startOfDay } from './datepicker.utils';

let _datepickerIdCounter = 0;

@Component({
  selector: 'n-datepicker',
  standalone: true,
  imports: [DatepickerCalendarComponent, LabelComponent],
  template: `
    <div class="flex flex-col" data-slot="root">

      @if (nLabel()) {
        <n-label [nFor]="datepickerId()" [nRequired]="nRequired()" [nDisabled]="isDisabled()">
          {{ nLabel() }}
        </n-label>
      }

      <button
        #trigger
        type="button"
        [id]="datepickerId()"
        data-slot="trigger"
        role="combobox"
        [attr.aria-haspopup]="'dialog'"
        [attr.aria-expanded]="open()"
        [attr.aria-controls]="contentId()"
        [attr.aria-label]="nLabel() ? null : nAriaLabel() || null"
        [attr.aria-describedby]="describedBy()"
        [attr.aria-invalid]="hasError() ? true : null"
        [attr.aria-required]="nRequired() ? true : null"
        [attr.data-state]="open() ? 'open' : 'closed'"
        [disabled]="isDisabled()"
        [class]="triggerClasses()"
        (click)="toggle()"
        (keydown)="handleTriggerKeydown($event)"
      >
        <span class="truncate">
          {{ displayLabel() || nPlaceholder() || 'Selecione uma data' }}
        </span>
        <svg
          aria-hidden="true"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          class="h-4 w-4 shrink-0 opacity-60 ml-2"
        >
          <rect x="3" y="4" width="18" height="18" rx="2" stroke-linecap="round" stroke-linejoin="round" />
          <path d="M16 2v4M8 2v4M3 10h18" stroke-linecap="round" stroke-linejoin="round" />
        </svg>
      </button>

      <ng-template #panel>
        <n-datepicker-calendar
          [nId]="contentId()"
          [nClass]="'min-w-[18rem]'"
          [nAutoFocus]="true"
          (nClear)="clear()"
        />
      </ng-template>

      @if (hasError()) {
        <p [id]="errorId()" class="mt-1 text-xs text-destructive animate-error-in" role="alert" data-slot="error">
          {{ nError() }}
        </p>
      }

      @if (nHint() && !hasError()) {
        <p [id]="hintId()" class="mt-1 text-xs text-muted-foreground" data-slot="hint">
          {{ nHint() }}
        </p>
      }

    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
  providers: [
    {
      provide: DATEPICKER_CTX,
      useFactory: (cmp: DatepickerComponent) => cmp.context,
      deps: [forwardRef(() => DatepickerComponent)],
    },
  ],
})
export class DatepickerComponent implements ControlValueAccessor, AfterViewInit, OnDestroy {
  readonly nValue        = model<Date | null>(null);
  readonly nMin          = input<Date | null>(null);
  readonly nMax          = input<Date | null>(null);
  readonly nDisabledDate = input<DisabledDateFn | null>(null);
  readonly nLocale       = input<string>(typeof navigator !== 'undefined' ? navigator.language : 'en-US');
  readonly nWeekStartsOn = input<0 | 1>(0);
  readonly nFormat       = input<Intl.DateTimeFormatOptions | null>(null);
  readonly nShowToday    = input<boolean>(true);
  readonly nClearable    = input<boolean>(true);

  readonly nLabel       = input<string>('');
  readonly nPlaceholder = input<string>('');
  readonly nDisabled    = input<boolean>(false);
  readonly nRequired    = input<boolean>(false);
  readonly nError       = input<string | null>(null);
  readonly nHint        = input<string | null>(null);
  readonly nClass       = input<string>('');
  readonly nAriaLabel   = input<string>('');
  readonly nId          = input<string>('');
  readonly nSize        = input<DatepickerSize>('default');

  readonly nChange     = output<Date | null>();
  readonly nOpenChange = output<boolean>();

  private readonly _staticId = `n-datepicker-${++_datepickerIdCounter}`;
  private readonly _form     = injectFormControl<Date | null>(this);
  private readonly _open     = signal(false);
  private readonly _overlay  = inject(Overlay);
  private readonly _vcr      = inject(ViewContainerRef);

  @ViewChild('trigger', { static: false }) private _triggerEl?: ElementRef<HTMLButtonElement>;
  @ViewChild('panel', { static: true }) private _panelTpl!: TemplateRef<unknown>;

  private _overlayRef: OverlayRef | null = null;
  private _portal: TemplatePortal | null = null;
  private _backdropSub?: Subscription;

  protected readonly datepickerId = computed(() => this.nId() || this._staticId);
  protected readonly contentId    = computed(() => `${this.datepickerId()}-content`);
  protected readonly errorId      = computed(() => `${this.datepickerId()}-error`);
  protected readonly hintId       = computed(() => `${this.datepickerId()}-hint`);

  protected readonly open = this._open.asReadonly();

  protected readonly isDisabled = computed(() => this.nDisabled() || this._form.disabledByForm());
  protected readonly hasError   = computed(
    () => !!this.nError() || (this._form.controlInvalid() && this._form.controlTouched()),
  );

  protected readonly describedBy = computed<string | null>(() => {
    if (this.hasError()) return this.errorId();
    if (this.nHint())   return this.hintId();
    return null;
  });

  protected readonly displayLabel = computed(() => {
    const v = this.nValue();
    if (!v) return '';
    return formatDate(v, this.nLocale(), this.nFormat() ?? undefined);
  });

  protected readonly triggerClasses = computed(() =>
    mergeClasses(
      datepickerTriggerVariants({ nSize: this.nSize(), empty: !this.nValue() }),
      this.nClass(),
    ),
  );

  readonly context: DatepickerContext = {
    value: this.nValue,
    min: this.nMin,
    max: this.nMax,
    disabledDate: this.nDisabledDate,
    locale: this.nLocale,
    weekStartsOn: this.nWeekStartsOn,
    disabled: this.isDisabled,
    selectDate: (date: Date) => this.commit(date),
  };

  ngAfterViewInit(): void {
    this._portal = new TemplatePortal(this._panelTpl, this._vcr);
  }

  ngOnDestroy(): void {
    this.detach();
  }

  protected toggle(): void {
    if (this.isDisabled()) return;
    if (this._open()) this.close(true);
    else this.openPanel();
  }

  private openPanel(): void {
    if (this._open()) return;
    this._open.set(true);
    this.nOpenChange.emit(true);
    this.attach();
  }

  private close(returnFocus: boolean): void {
    if (!this._open()) return;
    this._open.set(false);
    this.nOpenChange.emit(false);
    this.detach();
    this._form.notifyTouched();
    if (returnFocus) queueMicrotask(() => this._triggerEl?.nativeElement.focus());
  }

  protected clear(): void {
    this.nValue.set(null);
    this._form.notifyChange(null);
    this.nChange.emit(null);
    this.close(true);
  }

  private commit(date: Date): void {
    const next = startOfDay(date);
    this.nValue.set(next);
    this._form.notifyChange(next);
    this.nChange.emit(next);
    this.close(true);
  }

  protected handleTriggerKeydown(event: KeyboardEvent): void {
    if (event.key === 'ArrowDown' || event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.openPanel();
    }
  }

  private attach(): void {
    const trigger = this._triggerEl?.nativeElement;
    if (!trigger || !this._portal) return;
    if (this._overlayRef?.hasAttached()) return;

    const positions = this.buildPositions();
    const config = new OverlayConfig({
      positionStrategy: this._overlay
        .position()
        .flexibleConnectedTo(trigger)
        .withPositions(positions)
        .withFlexibleDimensions(false)
        .withPush(true),
      scrollStrategy: this._overlay.scrollStrategies.reposition(),
      hasBackdrop: true,
      backdropClass: 'cdk-overlay-transparent-backdrop',
    });

    this._overlayRef = this._overlay.create(config);
    this._overlayRef.attach(this._portal);
    this._backdropSub = this._overlayRef.backdropClick().subscribe(() => this.close(false));
    this._overlayRef.keydownEvents().subscribe(event => {
      if (event.key === 'Escape') {
        event.preventDefault();
        this.close(true);
      } else if (event.key === 'Tab') {
        this.close(false);
      }
    });
  }

  private detach(): void {
    this._backdropSub?.unsubscribe();
    this._backdropSub = undefined;
    if (this._overlayRef?.hasAttached()) this._overlayRef.detach();
    this._overlayRef?.dispose();
    this._overlayRef = null;
  }

  private buildPositions(): ConnectedPosition[] {
    const offset = 4;
    return [
      { originX: 'start', originY: 'bottom', overlayX: 'start', overlayY: 'top', offsetY: offset },
      { originX: 'start', originY: 'top',    overlayX: 'start', overlayY: 'bottom', offsetY: -offset },
      { originX: 'end',   originY: 'bottom', overlayX: 'end',   overlayY: 'top', offsetY: offset },
      { originX: 'end',   originY: 'top',    overlayX: 'end',   overlayY: 'bottom', offsetY: -offset },
    ];
  }

  writeValue(v: Date | null | undefined): void {
    this.nValue.set(v ?? null);
  }
  registerOnChange(fn: (v: Date | null) => void): void {
    this._form.setOnChange(fn);
  }
  registerOnTouched(fn: () => void): void {
    this._form.setOnTouched(fn);
  }
  setDisabledState(isDisabled: boolean): void {
    this._form.setDisabledByForm(isDisabled);
  }
}

import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
  viewChild,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DATEPICKER_CTX, type DisabledDateFn } from './datepicker.tokens';
import { datepickerDayVariants } from './datepicker.variants';
import {
  addDays,
  addMonths,
  addYears,
  buildMonthGrid,
  clamp,
  formatDate,
  formatMonthYear,
  getWeekdayLabels,
  isAfter,
  isBefore,
  isSameDay,
  startOfDay,
  startOfMonth,
} from './datepicker.utils';

@Component({
  selector: 'n-datepicker-calendar',
  standalone: true,
  template: `
    <div
      #root
      [id]="nId() || null"
      data-slot="content"
      role="dialog"
      [attr.aria-label]="'Calendário'"
      [class]="rootClasses()"
      (keydown)="handleKeydown($event)"
    >
      <div data-slot="header" class="flex items-center justify-between mb-3">
        <button
          type="button"
          class="inline-flex h-7 w-7 items-center justify-center rounded-md hover:bg-accent disabled:opacity-30 disabled:cursor-not-allowed"
          [disabled]="!canGoPrev()"
          [attr.aria-label]="'Mês anterior'"
          (click)="goMonth(-1)"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="h-4 w-4">
            <path d="m15 18-6-6 6-6" stroke-linecap="round" stroke-linejoin="round" />
          </svg>
        </button>

        <div class="text-sm font-medium capitalize" aria-live="polite">
          {{ headerLabel() }}
        </div>

        <button
          type="button"
          class="inline-flex h-7 w-7 items-center justify-center rounded-md hover:bg-accent disabled:opacity-30 disabled:cursor-not-allowed"
          [disabled]="!canGoNext()"
          [attr.aria-label]="'Próximo mês'"
          (click)="goMonth(1)"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="h-4 w-4">
            <path d="m9 18 6-6-6-6" stroke-linecap="round" stroke-linejoin="round" />
          </svg>
        </button>
      </div>

      <div role="grid" data-slot="grid" class="select-none">
        <div role="row" class="grid grid-cols-7 mb-1">
          @for (label of weekdayLabels(); track label) {
            <div role="columnheader" class="text-[0.7rem] font-medium text-muted-foreground text-center py-1 capitalize">
              {{ label }}
            </div>
          }
        </div>

        @for (week of weeks(); track $index) {
          <div role="row" class="grid grid-cols-7 gap-0.5">
            @for (cell of week; track cell.date.getTime()) {
              <button
                type="button"
                role="gridcell"
                data-slot="item"
                [tabindex]="isFocused(cell.date) ? 0 : -1"
                [attr.aria-selected]="isSelected(cell.date)"
                [attr.aria-disabled]="isDisabled(cell.date) ? true : null"
                [attr.aria-current]="cell.isToday ? 'date' : null"
                [disabled]="isDisabled(cell.date)"
                [class]="dayClasses(cell)"
                (click)="select(cell.date)"
                (focus)="onCellFocus(cell.date)"
              >
                {{ cell.date.getDate() }}
              </button>
            }
          </div>
        }
      </div>

      @if (showFooter()) {
        <div data-slot="footer" class="mt-3 flex items-center justify-between border-t border-border pt-3">
          @if (nShowToday()) {
            <button
              type="button"
              class="text-xs font-medium text-primary hover:underline disabled:opacity-30 disabled:cursor-not-allowed"
              [disabled]="isDisabled(today())"
              (click)="select(today())"
            >
              Hoje
            </button>
          } @else {
            <span></span>
          }
          @if (nClearable()) {
            <button
              type="button"
              class="text-xs font-medium text-muted-foreground hover:text-foreground hover:underline"
              (click)="clear()"
            >
              Limpar
            </button>
          }
        </div>
      }
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'block' },
})
export class DatepickerCalendarComponent implements AfterViewInit {
  readonly nValue        = input<Date | null>(null);
  readonly nMin          = input<Date | null>(null);
  readonly nMax          = input<Date | null>(null);
  readonly nDisabledDate = input<DisabledDateFn | null>(null);
  readonly nLocale       = input<string>(typeof navigator !== 'undefined' ? navigator.language : 'en-US');
  readonly nWeekStartsOn = input<0 | 1>(0);
  readonly nShowToday    = input<boolean>(true);
  readonly nClearable    = input<boolean>(true);
  readonly nClass        = input<string>('');
  readonly nAutoFocus    = input<boolean>(false);
  readonly nId           = input<string>('');

  readonly nChange = output<Date>();
  readonly nClear  = output<void>();

  private readonly _ctx = inject(DATEPICKER_CTX, { optional: true });
  private readonly _rootEl = viewChild<ElementRef<HTMLElement>>('root');

  protected readonly today = computed(() => startOfDay(new Date()));

  private readonly _resolvedValue = computed(() => this._ctx?.value() ?? this.nValue());
  private readonly _resolvedMin   = computed(() => this._ctx?.min() ?? this.nMin());
  private readonly _resolvedMax   = computed(() => this._ctx?.max() ?? this.nMax());
  private readonly _resolvedDisabledFn = computed(() => this._ctx?.disabledDate() ?? this.nDisabledDate());
  private readonly _resolvedLocale = computed(() => this._ctx?.locale() ?? this.nLocale());
  private readonly _resolvedWeekStart = computed(() => this._ctx?.weekStartsOn() ?? this.nWeekStartsOn());

  private readonly _viewDate = signal<Date>(startOfMonth(new Date()));
  private readonly _focusedDate = signal<Date>(startOfDay(new Date()));

  protected readonly weekdayLabels = computed(() =>
    getWeekdayLabels(this._resolvedLocale(), this._resolvedWeekStart()),
  );

  protected readonly cells = computed(() =>
    buildMonthGrid(this._viewDate(), this._resolvedWeekStart()),
  );

  protected readonly weeks = computed(() => {
    const all = this.cells();
    const out: typeof all[] = [];
    for (let i = 0; i < all.length; i += 7) out.push(all.slice(i, i + 7));
    return out;
  });

  protected readonly headerLabel = computed(() =>
    formatMonthYear(this._viewDate(), this._resolvedLocale()),
  );

  protected readonly canGoPrev = computed(() => {
    const min = this._resolvedMin();
    if (!min) return true;
    const prevMonthEnd = addDays(startOfMonth(this._viewDate()), -1);
    return !isBefore(prevMonthEnd, min);
  });

  protected readonly canGoNext = computed(() => {
    const max = this._resolvedMax();
    if (!max) return true;
    const nextMonthStart = startOfMonth(addMonths(this._viewDate(), 1));
    return !isAfter(nextMonthStart, max);
  });

  protected readonly showFooter = computed(() => this.nShowToday() || this.nClearable());

  constructor() {
    effect(() => {
      const v = this._resolvedValue();
      const target = v ? startOfMonth(v) : startOfMonth(new Date());
      this._viewDate.set(target);
      this._focusedDate.set(v ? startOfDay(v) : startOfDay(new Date()));
    });
  }

  ngAfterViewInit(): void {
    if (this.nAutoFocus()) {
      queueMicrotask(() => this.focusActiveCell());
    }
  }

  protected isSelected(date: Date): boolean {
    return isSameDay(date, this._resolvedValue());
  }

  protected isFocused(date: Date): boolean {
    return isSameDay(date, this._focusedDate());
  }

  protected isDisabled(date: Date): boolean {
    const min = this._resolvedMin();
    const max = this._resolvedMax();
    if (min && isBefore(date, min)) return true;
    if (max && isAfter(date, max)) return true;
    const fn = this._resolvedDisabledFn();
    if (fn && fn(date)) return true;
    return false;
  }

  protected dayClasses(cell: { date: Date; inMonth: boolean }): string {
    const date = cell.date;
    let state: 'default' | 'selected' | 'today' | 'outside' | 'disabled' = 'default';
    if (this.isDisabled(date)) state = 'disabled';
    else if (this.isSelected(date)) state = 'selected';
    else if (isSameDay(date, this.today())) state = 'today';
    else if (!cell.inMonth) state = 'outside';
    return mergeClasses(datepickerDayVariants({ state }));
  }

  protected rootClasses() {
    return mergeClasses(
      'rounded-md border border-border bg-popover p-3 text-popover-foreground shadow-md',
      this.nClass(),
    );
  }

  protected goMonth(delta: number): void {
    this._viewDate.set(startOfMonth(addMonths(this._viewDate(), delta)));
  }

  protected select(date: Date): void {
    if (this.isDisabled(date)) return;
    const clamped = clamp(startOfDay(date), this._resolvedMin(), this._resolvedMax());
    this._focusedDate.set(clamped);
    if (this._ctx) this._ctx.selectDate(clamped);
    this.nChange.emit(clamped);
  }

  protected clear(): void {
    this.nClear.emit();
  }

  protected onCellFocus(date: Date): void {
    this._focusedDate.set(date);
  }

  protected handleKeydown(event: KeyboardEvent): void {
    const focused = this._focusedDate();
    let next: Date | null = null;
    switch (event.key) {
      case 'ArrowLeft': next = addDays(focused, -1); break;
      case 'ArrowRight': next = addDays(focused, 1); break;
      case 'ArrowUp': next = addDays(focused, -7); break;
      case 'ArrowDown': next = addDays(focused, 7); break;
      case 'PageUp': next = event.shiftKey ? addYears(focused, -1) : addMonths(focused, -1); break;
      case 'PageDown': next = event.shiftKey ? addYears(focused, 1) : addMonths(focused, 1); break;
      case 'Home': {
        const start = this._resolvedWeekStart();
        const offset = (focused.getDay() - start + 7) % 7;
        next = addDays(focused, -offset);
        break;
      }
      case 'End': {
        const start = this._resolvedWeekStart();
        const offset = (focused.getDay() - start + 7) % 7;
        next = addDays(focused, 6 - offset);
        break;
      }
      case 'Enter':
      case ' ':
        event.preventDefault();
        this.select(focused);
        return;
      default: return;
    }
    if (!next) return;
    event.preventDefault();
    const clamped = clamp(next, this._resolvedMin(), this._resolvedMax());
    this._focusedDate.set(clamped);
    if (!isSameDay(this._viewDate(), clamped) && (clamped.getMonth() !== this._viewDate().getMonth() || clamped.getFullYear() !== this._viewDate().getFullYear())) {
      this._viewDate.set(startOfMonth(clamped));
    }
    queueMicrotask(() => this.focusActiveCell());
  }

  private focusActiveCell(): void {
    const root = this._rootEl()?.nativeElement;
    if (!root) return;
    const btn = root.querySelector<HTMLButtonElement>('button[role="gridcell"][tabindex="0"]');
    btn?.focus();
  }

  protected formatLabel(d: Date): string {
    return formatDate(d, this._resolvedLocale());
  }
}

import { InjectionToken, Signal } from '@angular/core';

export type DatepickerSize = 'sm' | 'default' | 'lg';
export type DisabledDateFn = (date: Date) => boolean;

export type DatepickerContext = {
  readonly value: Signal<Date | null>;
  readonly min: Signal<Date | null>;
  readonly max: Signal<Date | null>;
  readonly disabledDate: Signal<DisabledDateFn | null>;
  readonly locale: Signal<string>;
  readonly weekStartsOn: Signal<0 | 1>;
  readonly disabled: Signal<boolean>;
  selectDate(date: Date): void;
};

export const DATEPICKER_CTX = new InjectionToken<DatepickerContext>('DATEPICKER_CTX');

import { cva, type VariantProps } from 'class-variance-authority';

export const datepickerTriggerVariants = cva(
  [
    'flex w-full items-center justify-between rounded-md border border-input bg-background px-3',
    'text-sm text-foreground',
    'transition-all duration-200',
    'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:border-ring',
    'data-[state=open]:ring-2 data-[state=open]:ring-ring data-[state=open]:ring-offset-2 data-[state=open]:border-ring data-[state=open]:outline-none',
    'disabled:cursor-not-allowed disabled:opacity-50',
    'aria-invalid:border-destructive aria-invalid:ring-destructive',
    'cursor-pointer',
  ],
  {
    variants: {
      nSize: {
        sm: 'h-8 px-2 text-xs',
        default: 'h-10 px-3 text-sm',
        lg: 'h-12 px-4 text-base',
      },
      empty: {
        true: 'text-muted-foreground',
        false: '',
      },
    },
    defaultVariants: { nSize: 'default', empty: false },
  },
);

export type DatepickerTriggerVariants = VariantProps<typeof datepickerTriggerVariants>;

export const datepickerDayVariants = cva(
  [
    'inline-flex h-9 w-9 items-center justify-center rounded-md text-sm',
    'transition-colors',
    'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
    'disabled:cursor-not-allowed disabled:opacity-30',
  ],
  {
    variants: {
      state: {
        default: 'hover:bg-accent hover:text-accent-foreground cursor-pointer',
        selected: 'bg-primary text-primary-foreground hover:bg-primary/90 cursor-pointer',
        today: 'border border-primary text-foreground hover:bg-accent cursor-pointer',
        outside: 'text-muted-foreground/40 hover:bg-accent/40 cursor-pointer',
        disabled: 'text-muted-foreground/30 cursor-not-allowed',
      },
    },
    defaultVariants: { state: 'default' },
  },
);

export type DatepickerDayVariants = VariantProps<typeof datepickerDayVariants>;

export function startOfDay(d: Date): Date {
  const x = new Date(d);
  x.setHours(0, 0, 0, 0);
  return x;
}

export function startOfMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), 1);
}

export function endOfMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth() + 1, 0);
}

export function addDays(d: Date, n: number): Date {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  return x;
}

export function addMonths(d: Date, n: number): Date {
  const x = new Date(d);
  const day = x.getDate();
  x.setDate(1);
  x.setMonth(x.getMonth() + n);
  const last = endOfMonth(x).getDate();
  x.setDate(Math.min(day, last));
  return x;
}

export function addYears(d: Date, n: number): Date {
  return addMonths(d, n * 12);
}

export function isSameDay(a: Date | null | undefined, b: Date | null | undefined): boolean {
  if (!a || !b) return false;
  return (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );
}

export function isSameMonth(a: Date, b: Date): boolean {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth();
}

export function clamp(d: Date, min: Date | null, max: Date | null): Date {
  if (min && d < min) return min;
  if (max && d > max) return max;
  return d;
}

export function isBefore(a: Date, b: Date): boolean {
  return startOfDay(a).getTime() < startOfDay(b).getTime();
}

export function isAfter(a: Date, b: Date): boolean {
  return startOfDay(a).getTime() > startOfDay(b).getTime();
}

export type CalendarCell = {
  date: Date;
  inMonth: boolean;
  isToday: boolean;
};

export function buildMonthGrid(viewDate: Date, weekStartsOn: 0 | 1 = 0): CalendarCell[] {
  const today = startOfDay(new Date());
  const first = startOfMonth(viewDate);
  const offset = (first.getDay() - weekStartsOn + 7) % 7;
  const gridStart = addDays(first, -offset);
  const cells: CalendarCell[] = [];
  for (let i = 0; i < 42; i++) {
    const date = addDays(gridStart, i);
    cells.push({
      date,
      inMonth: date.getMonth() === viewDate.getMonth(),
      isToday: isSameDay(date, today),
    });
  }
  return cells;
}

export function getWeekdayLabels(locale: string, weekStartsOn: 0 | 1 = 0): string[] {
  const fmt = new Intl.DateTimeFormat(locale, { weekday: 'short' });
  const labels: string[] = [];
  const base = new Date(2024, 0, 7);
  for (let i = 0; i < 7; i++) {
    labels.push(fmt.format(addDays(base, i + weekStartsOn)));
  }
  return labels;
}

export function formatDate(d: Date | null, locale: string, options?: Intl.DateTimeFormatOptions): string {
  if (!d) return '';
  const opts: Intl.DateTimeFormatOptions = options ?? { year: 'numeric', month: 'short', day: '2-digit' };
  return new Intl.DateTimeFormat(locale, opts).format(d);
}

export function formatMonthYear(d: Date, locale: string): string {
  return new Intl.DateTimeFormat(locale, { year: 'numeric', month: 'long' }).format(d);
}

